const q = $input.first().json.query || {};
const complaintId = parseInt(q.complaintId);
if (!complaintId) return [{ json: { error: 'complaintId required' } }];

const sql = `SELECT 'escalation' AS record_type, id, escalationlevel, ticketno, closuredate AS edc, NULL AS remarks, NULL AS status, created FROM vmm_vendorescalations WHERE complaintid = ${complaintId} AND is_deleted='No' UNION ALL SELECT 'log' AS record_type, id, NULL AS escalationlevel, NULL AS ticketno, NULL AS edc, remarks, status, created FROM vmm_complaintlogs WHERE complaintid = ${complaintId} AND is_deleted='No' ORDER BY created ASC`;

return [{ json: { sql, complaintId } }];

const rows = $input.all().map(i => i.json);
const complaintId = $('Build History Query').first().json.complaintId;

function bufStr(v) {
  if (v == null) return null;
  if (typeof v === 'object' && v.type === 'Buffer' && Array.isArray(v.data)) {
    try { return new TextDecoder().decode(new Uint8Array(v.data)); } catch { return ''; }
  }
  return v;
}

const escalations = rows
  .filter(r => r.record_type === 'escalation')
  .map(r => ({ id: r.id, escalationlevel: r.escalationlevel, ticketno: bufStr(r.ticketno), edc: r.edc, created: r.created }));

const logs = rows
  .filter(r => r.record_type === 'log')
  .map(r => ({ id: r.id, remarks: bufStr(r.remarks), status: bufStr(r.status), created: r.created }));

return [{ json: { success: true, complaintId, escalations, logs } }];
